        return (
          <div key={i} className="chat-bubble user bubble-animate" style={{ animationDelay: `${i * 25}ms` }}>
            <div className="bubble-role-label">YOU</div>
            <div className="bubble-text">{msg.text}</div>
          </div>
        );
      })}
      {loading && <TypingIndicator />}
      <div ref={bottomRef} />
    </div>
  );
}
